examples.fromCode:
interface Coordinate {
  x: number;
  y: number;
}

function createCoordinate(x: number, y: number): Coordinate {
  return { x, y };
}

examples.toCode:
#include <stdlib.h>

typedef struct {
    double x;
    double y;
} Coordinate;

Coordinate* create_coordinate(double x, double y) {
    Coordinate* coord = (Coordinate*)malloc(sizeof(Coordinate));
    if (coord != NULL) {
        coord->x = x;
        coord->y = y;
    }
    return coord;
}

examples.fromCode:
function calculateSum(numbers: number[]): number {
  return numbers.reduce((acc, val) => acc + val, 0);
}

examples.toCode:
#include <stddef.h>

long long calculate_sum(const int* numbers, size_t count) {
    long long sum = 0;
    for (size_t i = 0; i < count; ++i) {
        sum += numbers[i];
    }
    return sum;
}
